import React, { Component } from "react";
// import './../SignUp/Log.css';
import axios from "axios";

export default class SignUp extends Component {

    constructor(props) {
        super(props);
        state = {
            name: "",
            Email :"",
            password:"",
            role:0

        };
      }


      handleChange(e){
        this.setState({
         [e.target.name]:e.target.value,
        })
    } ;


//     handleSubmit(e){
//         e.preventDefault();
//    axios.post("http://localhost:5000/signup",{ 
//     name:this.state.name,
//     email :this.state.Email,
//     password:this.state.password,

//   }).then((res)  => {
//    console.log(res.data) // array of object
//  }).catch((err) => { 
//    console.log(err);
//  });
//   }



  handleSubmit(e){
    e.preventDefault();
   if (state.button === 1){
        this.setState({
            role:1
        })
    }else {
        this.setState({
            role:0
        })
    }
axios.post("http://localhost:5000/signup",{ 
username:this.state.name,
email :this.state.Email,
password:this.state.password,
role: this.state.role

}).then((res)  => {
console.log(res.data) // array of object
}).catch((err) => { 
console.log(err);
});
}



    render() {
        return (
            <form  onSubmit={this.handleSubmit.bind(this)}
            >
                <h3>Sign Up</h3>



                <div className="form-group">
                    <label>name</label>
                    <input type="text"   value= {this.state.name} name="name" onChange={this.handleChange.bind(this)} className="form-control" placeholder="name" />
                </div>

                <div className="form-group">
                    <label>Email address</label>
                    <input type="email"   value= {this.state.Email} name="Email" onChange={this.handleChange.bind(this)} className="form-control" placeholder="Enter email" />
                </div>

                <div className="form-group">
                    <label>Password</label>
                    <input type="password"   value= {this.state.password} name="password" onChange={this.handleChange.bind(this)}   className="form-control" placeholder="Enter password" />
                </div>

                <button type="submit"    onClick={() => (state.button = 1)} name="company" className="btn btn-primary btn-block"> Register As A Company </button>
                <button type="submit"    onClick={() => (state.button = 0)}name ="volunteer" className="btn btn-primary btn-block">Register As A Volunteer</button>

                <p className="forgot-password text-right">
                    Already registered <a href="/login">sign in?</a>
                </p>
            </form>
        );
    }
}
